mapper.insert:
INSERT INTO seckill_reservation (
    user_id, coupon_id, status, reserve_at, trigger_at,
    retry_count, version, create_time, update_time
) VALUES (
    #{userId}, #{couponId}, #{status}, #{reserveAt}, #{triggerAt},
    #{retryCount}, #{version}, #{createTime}, #{updateTime}
)

mapper.select:
SELECT * FROM seckill_reservation
WHERE status = 'PENDING'
  AND trigger_at IS NOT NULL
  AND trigger_at < #{now}
ORDER BY id ASC
LIMIT #{limit}

mapper.update:
UPDATE seckill_reservation
SET status = 'PENDING',
    version = version + 1,
    update_time = NOW()
WHERE id IN (
    SELECT id FROM (
        SELECT id FROM seckill_reservation
        WHERE status = 'FIRING'
          AND COALESCE(fired_at, update_time) < #{before}
        ORDER BY id ASC
        LIMIT #{limit}
    ) t
)
